#include<bits/stdc++.h>
using namespace std;

int arr[5010],dp[1000004],n;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>arr[i];
        dp[i]=1;
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<i;j++){
            if(arr[j]<arr[i]){
                dp[i]=max(dp[i],dp[j]+1);
            }
        }
    }
    int sum=0;
    for(int i=1;i<=n;i++){
        sum=max(sum,dp[i]);
    }
    cout<<sum;
}
